module top_module(input [3:0] a, output reg [6:0] disp_out);always @ *
	begin
		case(a)
			4'b0000 : disp_out = 7'b0111111;
			4'b0001 : disp_out = 7'b0000110;
			4'b0010 : disp_out = 7'b1011011;
			4'b0011 : disp_out = 7'b1001111;
			4'b0100 : disp_out = 7'b1100110;
			4'b0101 : disp_out = 7'b1101101;
			4'b0110 : disp_out = 7'b1111101;
			4'b0111 : disp_out = 7'b0000111;
			4'b1000 : disp_out = 7'b1111111;
		endcase
	end


endmodule
